 1	import React from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 5	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { DescriptionList } from '@patternfly/react-core';
 8	
 9	import { MoreInformationDefaultProps } from '../utils/types';
10	
11	import Detail from './Detail';
12	
13	const MoreInformationDefault: React.FC<MoreInformationDefaultProps> = ({ textMoreInfoContent }) => {
14	  const { t } = useKubevirtTranslation();
15	  return (
16	    <>
17	      {textMoreInfoContent || (
18	        <Trans ns="plugin__kubevirt-plugin" t={t}>
19	          <p>
20	            Clicking &quot;Launch Remote Viewer&quot; will download a .vv file and launch{' '}
21	            <i>Remote Viewer</i>
22	          </p>
23	          <p>
24	            <i>Remote Viewer</i> is available for most operating systems. To install it, search for
25	            it in GNOME Software or run the following:
26	          </p>
27	        </Trans>
28	      )}
29	      <DescriptionList className="pf-v6-c-description-list" isHorizontal>
30	        <Detail title={'RHEL, CentOS'} value={'sudo yum install virt-viewer'} />
31	        <Detail title={'Fedora'} value={'sudo dnf install virt-viewer'} />
32	        <Detail title={'Ubuntu, Debian'} value={'sudo apt-get install virt-viewer'} />
33	        <VirtualMachineDescriptionItem
34	          descriptionData={
35	            <div>
36	              {t('Download the MSI from ')}
37	              <a
38	                href={documentationURL.VIRT_MANAGER_DOWNLOAD}
39	                rel="noopener noreferrer"
40	                target="_blank"
41	              >
42	                virt-manager.org
43	              </a>
44	            </div>
45	          }
46	          descriptionHeader={t('Windows')}
47	        />
48	      </DescriptionList>
49	    </>
50	  );
51	};
52	
53	export default MoreInformationDefault;

